import{_ as r}from"./plugin-vue_export-helper-c27b6911.js";import{r as h,o as i,c,b as e,d as a,a as n,e as l}from"./app-100a6b97.js";const t={},o=e("h1",{id:"linux-笔记",tabindex:"-1"},[e("a",{class:"header-anchor",href:"#linux-笔记","aria-hidden":"true"},"#"),a(" Linux 笔记")],-1),s=e("div",{class:"hint-container warning"},[e("p",{class:"hint-container-title"},"该笔记尚未完成")],-1),u={href:"https://www.runoob.com/linux/linux-tutorial.html",target:"_blank",rel:"noopener noreferrer"},x=l('<h2 id="基本概念" tabindex="-1"><a class="header-anchor" href="#基本概念" aria-hidden="true">#</a> 基本概念</h2><h3 id="系统目录含义" tabindex="-1"><a class="header-anchor" href="#系统目录含义" aria-hidden="true">#</a> 系统目录含义</h3><h3 id="路径" tabindex="-1"><a class="header-anchor" href="#路径" aria-hidden="true">#</a> 路径</h3><h2 id="基本文件操作" tabindex="-1"><a class="header-anchor" href="#基本文件操作" aria-hidden="true">#</a> 基本文件操作</h2><h3 id="cd-进入文件夹" tabindex="-1"><a class="header-anchor" href="#cd-进入文件夹" aria-hidden="true">#</a> cd 进入文件夹</h3><h3 id="mkdir-新建文件夹" tabindex="-1"><a class="header-anchor" href="#mkdir-新建文件夹" aria-hidden="true">#</a> mkdir 新建文件夹</h3><h3 id="rmdir-删除文件夹" tabindex="-1"><a class="header-anchor" href="#rmdir-删除文件夹" aria-hidden="true">#</a> rmdir 删除文件夹</h3><h3 id="cp-复制文件" tabindex="-1"><a class="header-anchor" href="#cp-复制文件" aria-hidden="true">#</a> cp 复制文件</h3><h3 id="mv-移动文件" tabindex="-1"><a class="header-anchor" href="#mv-移动文件" aria-hidden="true">#</a> mv 移动文件</h3><h3 id="rm-删除文件" tabindex="-1"><a class="header-anchor" href="#rm-删除文件" aria-hidden="true">#</a> rm 删除文件</h3><h3 id="ls-列出目录及文件" tabindex="-1"><a class="header-anchor" href="#ls-列出目录及文件" aria-hidden="true">#</a> ls 列出目录及文件</h3><h3 id="ln-软连接" tabindex="-1"><a class="header-anchor" href="#ln-软连接" aria-hidden="true">#</a> ln 软连接</h3><h3 id="touch-创建文件" tabindex="-1"><a class="header-anchor" href="#touch-创建文件" aria-hidden="true">#</a> touch 创建文件</h3><h3 id="df-磁盘空间" tabindex="-1"><a class="header-anchor" href="#df-磁盘空间" aria-hidden="true">#</a> df 磁盘空间</h3><h2 id="shell-语法" tabindex="-1"><a class="header-anchor" href="#shell-语法" aria-hidden="true">#</a> shell 语法</h2><h2 id="文件权限" tabindex="-1"><a class="header-anchor" href="#文件权限" aria-hidden="true">#</a> 文件权限</h2><h3 id="文件属性" tabindex="-1"><a class="header-anchor" href="#文件属性" aria-hidden="true">#</a> 文件属性</h3><ul><li>文件类型 <ul><li><code>d</code> 目录文件</li><li><code>l</code> 软连接</li><li><code>c</code> 串行端口设备</li><li><code>-</code> 一般文件</li></ul></li><li>文件权限 <ul><li><code>r</code> 读取权限</li><li><code>w</code> 写入权限</li><li><code>x</code> 执行权限</li><li><code>-</code> 无权限</li></ul></li><li>文件属性字符 <ul><li>0 位表示文件类型</li><li>1-3 位确定文件所有者的权限 (owner, u)</li><li>4-6 位确定与文件所有者同组的权限 (group, g)</li><li>7-9 位确定其他用户的权限 (other, o)</li></ul></li><li>权限数字表示<br> 将文件属性字符的 1-3, 4-6, 7-9 位分别视为一个三位二进制数<br> 该二进制数的第一位对应 <code>r</code>, 第二位对应 <code>w</code>, 第三位对应 <code>x</code><br> 当取 <code>0</code> 时, 表示 <code>-</code> 即无权限<br> 例如 <code>761</code> 对应了属性字符 <code>rwxrw---x</code></li></ul><p>对于 root 用户, 不受权限影响</p><h3 id="chmod-修改文件权限" tabindex="-1"><a class="header-anchor" href="#chmod-修改文件权限" aria-hidden="true">#</a> chmod 修改文件权限</h3><h4 id="通过权限数字" tabindex="-1"><a class="header-anchor" href="#通过权限数字" aria-hidden="true">#</a> 通过权限数字</h4><p><code>chmod [-R] &lt;xyz&gt; &lt;file&gt;</code></p><ul><li><code>xyz</code> 文件新的权限数字</li><li><code>file</code> 文件或目录名</li><li><code>-R</code> 递归修改, 当启用此选项后, 将同时修改目录下的所有文件</li></ul><h4 id="通过符号类型" tabindex="-1"><a class="header-anchor" href="#通过符号类型" aria-hidden="true">#</a> 通过符号类型</h4><p><code>chmod [-R] u=&lt;ur&gt; g=&lt;gr&gt; o=&lt;or&gt; &lt;file&gt;</code></p><ul><li><code>ur</code> 文件所有者的权限字符</li><li><code>gr</code> 文件所有者同组用户的权限字符</li><li><code>or</code> 其他用户的权限字符</li><li><code>file</code> 文件或目录名</li></ul><h2 id="软件下载与安装" tabindex="-1"><a class="header-anchor" href="#软件下载与安装" aria-hidden="true">#</a> 软件下载与安装</h2><h3 id="wget" tabindex="-1"><a class="header-anchor" href="#wget" aria-hidden="true">#</a> wget</h3><h3 id="curl" tabindex="-1"><a class="header-anchor" href="#curl" aria-hidden="true">#</a> curl</h3><h3 id="apt" tabindex="-1"><a class="header-anchor" href="#apt" aria-hidden="true">#</a> apt</h3><h3 id="dpkg" tabindex="-1"><a class="header-anchor" href="#dpkg" aria-hidden="true">#</a> dpkg</h3><h3 id="tar" tabindex="-1"><a class="header-anchor" href="#tar" aria-hidden="true">#</a> tar</h3><h2 id="实用命令" tabindex="-1"><a class="header-anchor" href="#实用命令" aria-hidden="true">#</a> 实用命令</h2><h3 id="tree" tabindex="-1"><a class="header-anchor" href="#tree" aria-hidden="true">#</a> tree</h3><h3 id="screen" tabindex="-1"><a class="header-anchor" href="#screen" aria-hidden="true">#</a> screen</h3><h3 id="ps" tabindex="-1"><a class="header-anchor" href="#ps" aria-hidden="true">#</a> ps</h3>',36);function f(b,m){const d=h("ExternalLinkIcon");return i(),c("div",null,[o,s,e("p",null,[a("参考教程 "),e("a",u,[a("https://www.runoob.com/linux/linux-tutorial.html"),n(d)])]),x])}const g=r(t,[["render",f],["__file","linux.html.vue"]]);export{g as default};
